```hcl
# Terraform: MSK クラスターがパブリックにアクセス可能でないことを確認します
resource "aws_msk_cluster" "<example_resource_name>" {
  cluster_name           = "<example_resource_name>"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 2

  broker_node_group_info {
    client_subnets = [
      "<example_subnet_id_1>",
      "<example_subnet_id_2>",
    ]
    instance_type = "kafka.t3.small"

    connectivity_info {
      public_access {
        type = "DISABLED"  # 重要: ブローカーへのパブリックアクセスを無効にします
      }
    }
  }
}
